// ─── Função para seleccionar 3 pratos diários (mesmos durante o dia, mudam à meia-noite) ─
export const getDailySelection = () => {
    const today = new Date().toISOString().split('T')[0];
    const seed = today.split('-').reduce((acc, n) => acc + parseInt(n), 0);

    const pick = (arr, offset) => {
        const idx = Math.abs(Math.floor((seed * (offset + 1) * 7919) % arr.length));
        return arr[idx];
    };

    return [
        { ...pick(dailyMealsDB["Pequeno-almoço"], 0), category: "Pequeno-almoço" },
        { ...pick(dailyMealsDB["Almoço"], 1), category: "Almoço" },
        { ...pick(dailyMealsDB["Jantar"], 2), category: "Jantar" },
    ];
};